const a=(t,s="")=>{if(!t)return`${(s||"").replace(/\/+$/,"")}/api`;if(t.startsWith("http")||t.startsWith("//"))return t;const e=(s||"").replace(/\/+$/,""),r=t.startsWith("/")?t:`/${t}`;return`${e}/api${r}`},c=(t,s="")=>{if(!t)return s||"/";if(t.startsWith("http")||t.startsWith("//"))return t;const e=s.replace(/\/+$/,""),r=t.startsWith("/")?t:`/${t}`;return`${e}${r}`},i=(t,s="")=>{if(!t)return"";if(t.startsWith("http")||t.startsWith("//")||t.startsWith("blob:"))return t;const e=(s||"").replace(/\/+$/,""),r=t.replace(/^\/+/,"");if(r.startsWith("uploads/"))return`${e}/${r}`;const n=r.startsWith("storage/")?r.replace(/^storage\//,"uploads/"):`uploads/${r}`;return`${e}/${n}`};export{a,c as r,i as s};
